def transition(state, action):
    s = dict(state)
    name = action.get("name")
    params = action.get("params") or {}
    if s.get("finished"):
        return s
    if name == "call_tool":
        tool = params.get("tool")
        if tool in s.get("available_tools", []):
            s["called_tools"] = list(s.get("called_tools", [])) + [tool]
            s["pending"] = s.get("pending", 0) + 1
            s["steps"] = s.get("steps", 0) + 1
    elif name == "observe":
        if s.get("pending", 0) > 0:
            s["pending"] = s["pending"] - 1
            s["observed"] = s.get("observed", 0) + 1
            s["steps"] = s.get("steps", 0) + 1
    elif name == "finish":
        required = set(s.get("required_tools", []))
        called = set(s.get("called_tools", []))
        s["satisfied"] = required.issubset(called) and s.get("pending", 0) == 0
        s["finished"] = True
        s["steps"] = s.get("steps", 0) + 1
    return s

