def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' not in line:
            continue
        k, v = line.split(':', 1)
        k = k.strip().lower(); v = v.strip()
        if k == 'request':
            out['request'] = v
        elif k in ('tools', 'available'):
            out['available_tools'] = [t.strip() for t in v.split(',') if t.strip()]
        elif k in ('needs', 'required'):
            out['required_tools'] = [t.strip() for t in v.split(',') if t.strip()]
    return out
